#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long l,r,lson,rson,sum;
}a[30000010];
long long cnt,root[1000010];
long long build(long long l,long long r)
{
    long long x=++cnt;
    a[x].l=l;
    a[x].r=r;
    if(l==r)
    {
        scanf("%lld",&a[x].sum);
        return x;
    }
    long long mid=(l+r)>>1;
    a[x].lson=build(l,mid);
    a[x].rson=build(mid+1,r);
    a[x].sum=a[a[x].lson].sum+a[a[x].rson].sum;
    return x;
}
long long update(long long x,long long p,long long v)
{
    if(a[x].l>p||a[x].r<p)
    {
        return x;
    }
    long long now=++cnt;
    a[now]=a[x];
    if(a[x].l==a[x].r)
    {
        a[now].sum=v;
        return now;
    }
    a[now].lson=update(a[x].lson,p,v);
    a[now].rson=update(a[x].rson,p,v);
    a[now].sum=a[a[now].lson].sum+a[a[now].rson].sum;
    return now;
}
long long query(long long x,long long l,long long r)
{
    if(a[x].l>r||a[x].r<l)
    {
        return 0;
    }
    if(l<=a[x].l&&a[x].r<=r)
    {
        return a[x].sum;
    }
    return query(a[x].lson,l,r)+query(a[x].rson,l,r);
}
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    root[0]=build(1,n);
    for(long long i=1;i<=m;i++)
    {
        long long v,op,p,c;
        scanf("%lld%lld%lld",&v,&op,&p);
        root[i]=root[v];
        if(op==1)
        {
            scanf("%lld",&c);
            root[i]=update(root[i],p,c);
        }
        else
        {
            printf("%lld\n",query(root[i],p,p));
        }
    }
    return 0;
}
